         ),
         expectation(
             "Follow-Ups explicitly says there are no remaining follow-ups if none are provided.",
             contains_any(follow_ups, ["none", "no follow-up", "no follow ups", "no follow-ups"]),
             follow_ups or "missing Follow-Ups section body",
         ),
