 def iter_run_dirs(path: Path) -> list[tuple[int, Path]]:
     run_pairs: list[tuple[int, Path]] = []
     for eval_dir in sorted(path.glob("eval-*")):
         metadata = load_json(eval_dir / "eval_metadata.json")
